#include <bits/stdc++.h>
using namespace std;

class Curatare {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    struct BFS_entry {
        int row;
        int col;
        int dist;
        BFS_entry(int x, int y, int w)
        : row(x), col(y), dist(w) {}
    };

    int n, m;
    vector<vector<char>> matrix;
    vector<pair<int, int>> spaces;
    vector<pair<int, int>> robots;

    /* Functia citeste input-ul din fisier
     si il salveaza in atributele specifice */
    void read_input() {
        ifstream fin("curatare.in");
        fin >> n >> m;
        matrix.reserve(n);
        for (int i = 0; i < n; i++) {
            matrix[i].reserve(m);
            for (int j = 0; j < m; j++) {
                fin >> matrix[i][j];
            }
        }
        fin.close();
    }

    /* Gasirea drumurilor cu ajutorul BFS */
    int minDistances(BFS_entry source, int pos,
    vector<unordered_map<int, int>> &distances) {
        unordered_map<int, int> dists;
        vector<vector<bool>> visited(n, vector<bool>(m));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (matrix[i][j] == 'X')
                    visited[i][j] = true;
                else
                    visited[i][j] = false;
            }
        }
        queue<BFS_entry> q;
        q.push(source);
        visited[source.row][source.col] = true;
        while (!q.empty()) {
            BFS_entry p = q.front();
            q.pop();

            // Am gasit destinatia
            if (matrix[p.row][p.col] == 'S' || matrix[p.row][p.col] == 'R') {
                distances[pos].insert({p.row * m + p.col, p.dist});
            }

            // SUS
            if (p.row - 1 >= 0 &&
                visited[p.row - 1][p.col] == false) {
                q.push(BFS_entry(p.row - 1, p.col, p.dist + 1));
                visited[p.row - 1][p.col] = true;
            }

            // JOS
            if (p.row + 1 < n &&
                visited[p.row + 1][p.col] == false) {
                q.push(BFS_entry(p.row + 1, p.col, p.dist + 1));
                visited[p.row + 1][p.col] = true;
            }

            // STANGA
            if (p.col - 1 >= 0 &&
                visited[p.row][p.col - 1] == false) {
                q.push(BFS_entry(p.row, p.col - 1, p.dist + 1));
                visited[p.row][p.col - 1] = true;
            }

            // DREAPTA
            if (p.col + 1 < m &&
                visited[p.row][p.col + 1] == false) {
                q.push(BFS_entry(p.row, p.col + 1, p.dist + 1));
                visited[p.row][p.col + 1] = true;
            }
        }
        return -1;
    }

    /* Functia pentru backtracking */
    void backtracking(vector<bool> &checked, vector<int> &time,
            int &result, vector<unordered_map<int, int>> distances) {
        bool flag = true;
        for (int i = 0; i < checked.size(); i++) {
            flag = flag && checked[i];
        }

        if (flag) {
            int localMaximum = -1;
            for (int i = 0; i < time.size(); i++) {
                if (localMaximum < time[i])
                    localMaximum = time[i];
            }
            if (localMaximum < result) {
                result = localMaximum;
            }

            return;
        }

        for (int i = 0; i < robots.size(); i++) {
            for (int j = 0; j < spaces.size(); j++) {
                if (checked[j] == true
                || distances[j][robots[i].first * m + robots[i].second] == 0)
                    continue;

                checked[j] = true;
                time[i] += distances[j][robots[i].first * m + robots[i].second];
                BFS_entry old(robots[i].first, robots[i].second, 0);

                vector<unordered_map<int, int>> distances_copy = distances;

                vector<int> old_distances(spaces.size());
                robots[i].first = spaces[j].first;
                robots[i].second = spaces[j].second;

                backtracking(checked, time, result, distances);

                robots[i].first = old.row;
                robots[i].second = old.col;
                distances = distances_copy;
                time[i] -= distances[j][robots[i].first * m + robots[i].second];

                checked[j] = false;
            }
        }
    }

    /* Functia rezolva task-ul */
    int get_result() {
        // Adaug spatiile de curatat si robotii in liste
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (matrix[i][j] == 'S')
                    spaces.push_back({i, j});
                else if (matrix[i][j] == 'R')
                    robots.push_back({i, j});
            }
        }
        // Gasesc distantele minime dinspre spatii catre roboti/spatii
        vector<unordered_map<int, int>> distances(spaces.size());
        int max = robots.size();
        if (spaces.size() > max) {
            max = spaces.size();
        }
        for (int i = 0; i < spaces.size(); i++) {
            minDistances(BFS_entry(spaces[i].first,
                spaces[i].second, 0), i, distances);
        }

        // Apelez backtracking-ul pentru a gasi solutia
        int result = INT_MAX;
        vector<bool> checked(spaces.size(), false);
        vector<int> time(robots.size(), 0);
        backtracking(checked, time, result, distances);

        return result;
    }

    /* Functia scrie output-ul in fisier */
    void print_output(int res) {
        ofstream fout("curatare.out");
        fout << res << endl;
        fout.close();
    }
};

int main() {
    // Instantiez clasa Curatare
    auto* curatare = new (nothrow) Curatare();
    if (!curatare) {
        cerr << "new failed!\n";
        return -1;
    }
    // Apelez metoda solve pentru a rezolva task-ul
    curatare->solve();
    // Dealoc memoria alocata pentru instanta clasei
    delete curatare;

    return 0;
}

